text:
Also, generate MOVED entries:

git diff -C05 --no-prefix --name-status origin/trunk...python-flavors |\
  awk '$1 !~ /^M/ && /Makefile/ {
    sub("/Makefile", "", $2);
    n=$2;
    sub("/py3.?-", "/py-", n);
    print $2 "|" n "@python3|'`date +%Y-%m-%d`'|Moved to a flavored, generic, version"
  }'
